var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"뭘 하고 있었지?","JPN":"何をしていたんだ？","ENG":"What was I doing?","TWN":"我在做什麼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"나는 왜, 이런 곳에…….","JPN":"私はどうして、こんなところに……","ENG":"Why am I... in a place like this...?","TWN":"我怎麼會在這裡……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"하하. 하하…!","JPN":"ハハ。ハハハ…！","ENG":"Haha. Haha...!","TWN":"哈哈，哈哈…！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"그래. 아무도 <color=#ffd34c>우리</color>를 이해하지 못해.","JPN":"そう。誰も<color=#ffd34c>私たち</color>のことを理解できない。","ENG":"Yeah. No one will understand <color=#ffd34c>us</color>.","TWN":"沒錯，沒有人理解<color=#ffd34c>我們</color>。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이곳에서는 슬픔도, 원한도, 고통도, 아무것도 존재하지 않아.","JPN":"ここには悲しみも、恨みも、苦しみも、何も存在しない。","ENG":"Nothing exists here. Not even sorrow, resentment, or pain.","TWN":"在這裡，傷心、憎恨、痛苦，這些都不存在。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"아아, 이런 황홀한 기분을 느낄 수 있을 줄이야…!","JPN":"ああ、こんなうっとりとした気分を味わえるなんて……！","ENG":"Ahh, I never knew I could feel this ecstatic...!","TWN":"啊～沒想到可以感受到如此豐富的情緒…！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRA_CORRUPT_NULL_SHADOW","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRA_CORRUPT_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이런, 감정에 도취한 나머지 못 볼 꼴을 보인 것 같구나.","JPN":"おっと、感情に溺れて見にくい姿を見せてしまったようだ。","ENG":"Oh, I'm embarrassed to show you how emotionally high I was.","TWN":"糟糕，真是失態，竟然讓人看到我如此陶醉的樣子。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"걱정하지 마렴. 네가 누군진 모르겠지만, 곧 나와 같이 아무런 걱정도 없게 해줄게.","JPN":"心配するな。お前が誰なのかはわからないが、すぐ私みたいに何の心配もないようにしてやる。","ENG":"No worries. I don't know who you are, but I'll make your worries go away, just like me.","TWN":"放心，我不知道你是誰，但我現在就可以讓你和我一起脫離一切的煩惱。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"아무런… 걱정도… 없…","JPN":"何の……心配……も……","ENG":"Make... your worries...","TWN":"脫離…一切的…"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이…?","JPN":"な……？","ENG":"go away...?","TWN":"煩惱…？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"빌어먹을. 하루 세끼 풀죽은 대체 누구 머리에서 나온 아이디어야?","JPN":"くそ。三食お粥って、誰のアイデアだ？","ENG":"Ugh. Whose idea was it to eat grass porridge for every meal?","TWN":"該死，到底是誰想到一天三餐都吃野菜粥的？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"엥? 맛이 없었나요? 간은 분명 딱 맞았는데!","JPN":"えっ？　まずいですか？　塩かげんはちょうど良かったんですけど！","ENG":"Huh? Does it taste bad? I seasoned it and all!","TWN":"嗯？不好吃嗎？我明明有加鹽巴呀！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"간이고 자시고 네가 쓸데없는 부품을 산 탓이잖아. 망할 꼬맹이.","JPN":"塩かげんも何も、お前がくだらない部品を買うからだろう。クソガキ。","ENG":"Who cares about seasoning? This is all because you bought those useless parts, you brat.","TWN":"重點不是有沒有調味，重點是配菜的問題，臭小鬼。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"반찬 투정은 삼가십시오, 리타. 나이도 먹을 만큼 먹지 않았습니까.","JPN":"ご飯の文句は止してください、リタ。もういい年ではありませんか。","ENG":"Stop complaining about your food, Rita. I thought you were more mature than that.","TWN":"不要挑食，麗塔。都已經這麼大年紀還嫌東嫌西的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"미뢰를 통한 무의미한 정보 전달에 구애받지 않는다는 건 큰 장점입니다.","JPN":"味蕾という無意味な情報提供の手段にとらわれないということは大きな長所です。","ENG":"It has the enormous benefit of not being limited by meaningless information delivered via taste buds.","TWN":"野菜粥最大的優點，就是可以跳脫味蕾的限制。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"아, 맞다! 대표님 서랍에 있던 작은 상자, 위험한 물건 같길래 버렸어요!","JPN":"あっ、そうだ！　代表の引き出しにあった小さな箱、危ないものみたいだから捨てました！","ENG":"Oh, right! Boss, the tiny box you had in your drawer, I threw it away because it seemed dangerous!","TWN":"對了！BOSS，你抽屜裡有個小箱子，感覺好像是什麼危險物品，我就把它丟掉囉！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"미끌미끌거리던데 저 잘했죠?","JPN":"ぬるぬるしてましたけど、よくやったでしょう？","ENG":"It was all slippery. Did I do a good job?","TWN":"整個都油油的，我很棒吧？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_HORIZON_NULL_NULL","text":{"KOREA":"……윤활유 값은 ■■ 월급에서 까겠습니다.","JPN":"……潤滑油のお代は、■■の給料から引くことにします。","ENG":"...I'll deduct the cost of the lubricants from ■■■■'s salary.","TWN":"……潤滑油的錢會從■■的薪水裡面扣。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"댕-!","JPN":"ガーン！","ENG":"DUN-!","TWN":"噹-！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하아, 가끔씩 보면 아무 걱정도 없는 것 같단 말이지….","JPN":"はあ、時々何の心配もないように見えるんだな……","ENG":"*Sigh.* Sometimes, I think you really don't have any worries...","TWN":"哀，你還真是唯恐天下不亂…"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"적당히 해. 가뜩이나 없는 사무실 더 빈곤하게 하지 말고.","JPN":"いい加減にしろ。そうでなくても何もない事務所なのに、もっとボロボロにするんじゃない。","ENG":"Go easy, all right? And try not to impoverish our office when it already has nothing left.","TWN":"不要太超過，公司已經家徒四壁，你是嫌公司還不夠窮嗎？"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"에이, 아무것도 없긴 왜 없어요? 언니랑, 대표님이랑… 아, 그리고 덩실이도 있잖아요!","JPN":"ええ？　何もなくはないですよ。お姉ちゃんと、代表と……あ、それにふわりもいます！","ENG":"Huh? What do you mean there's nothing here? There's you, Boss... Oh! And Dangler!","TWN":"怎麼會呢？哪有家徒四壁？有姊姊，有BOSS…還有刀刀啊！"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"저는 이것만으로 세상을 다 가진 기분인걸요?","JPN":"私はこれだけでも世界を手にした気分ですよ。","ENG":"I feel like I have everything in the world with you three!","TWN":"只要有你們我就覺得我擁有了全世界。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"엄마, 아빠뿐만 아니라… 언니랑 대표님도 가족이고.","JPN":"お母さん、お父さんだけじゃなくて……お姉ちゃんと代表も家族ですし。","ENG":"It's not just Mom and Dad, but... Rita and Boss are also family.","TWN":"不只是爸爸媽媽…姊姊和BOSS也是我的家人。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FOOLSDAY_DASH_NULL_NULL","text":{"KOREA":"저한테는 여기가 돌아올 집이에요.","JPN":"私にはここが帰ってくる家です。","ENG":"And this place is where I call home.","TWN":"這裡就是我的家。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까, 언니.","JPN":"だから、お姉ちゃん。","ENG":"So, Rita.","TWN":"所以，姊姊。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_DASH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"같이 돌아가요.","JPN":"一緒に帰りましょう。","ENG":"Let's go back together.","TWN":"我們一起回去吧。"},"stage":{"bg":"WHITE","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"집으로.","JPN":"お家に。","ENG":"Let's go home.","TWN":"回我們的家。"},"stage":{"bg":"WHITE","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니이이이이-!","JPN":"お姉ちゃーーーん！","ENG":"RITAAAAA-!","TWN":"姊姊～～！！"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"괜찮으세요, 언니?","JPN":"大丈夫ですか？　お姉ちゃん。","ENG":"Are you all right?","TWN":"姊姊你沒事吧?"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"…꼬맹이?","JPN":"……ガキ？","ENG":"...Kid?","TWN":"…小鬼？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"너, 여긴 어떻게….","JPN":"お前、どうやってここに……","ENG":"How... How are you...","TWN":"你怎麼會在這裡…"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진공관 맙소사. 바니걸은 싫다면서 코스프레 바니걸이라니. 이 무슨 기괴한.","JPN":"オーマイ真空管。バーニーガールは嫌だって言ったくせにコスプレバーニーガールとは。なんと奇怪な。","ENG":"Oh my diodes. You said you hated bunny girls, but now you're cosplaying as a bunny girl. What a bizarre situation.","TWN":"我的真空管，你不是討厭兔女郎嗎？怎麼還COS成兔女郎？真是矛盾。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>인생 살면서 이딴 옷을 두 번 입을 일은 없을 테니까.</color>","JPN":"これからのもう二度とこんな服を着ることはないだろうからな。","ENG":"<color=#ffd34c>This will be the only time I wear something like this ever again.</color>","TWN":"我這輩子絕對不會再穿第二次！"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"축하드립니다, 리타. 작심삼일은커녕 하루도 못 갔군요.","JPN":"おめでとうございます、リタ。三日坊主はおろか、一日も過ぎていません。","ENG":"Congratulations, Rita. Your resolve did not even last a day.","TWN":"麗塔，恭喜你，不要說三分鐘熱度，你連三秒鐘都沒有。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"호라이즌? 너, 어느 틈에 소체를 갈아 끼운 거야?","JPN":"ホライズン？　お前、いつの間に素体を切り替えたんだ？","ENG":"Horizon? When did you change bodies?","TWN":"地平線？你什麼時候變成無人機的樣子進來的？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"설마 그 정도로 시간이 흐른 건가?","JPN":"まさか、そんなに時間が過ぎてるのか？","ENG":"Did time pass by that much already?","TWN":"時間有過得這麼快嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"넌센스지만 아티팩트가 지닌 힘이겠죠. 사용자의 부정을 이끌어내, 환상을 구현해내는 것 같습니다.","JPN":"ナンセンスですが、アーティファクトが持つ力でしょう。使用者の不浄を引き出し、幻を具現させるようです。","ENG":"It's nonsense, but it might be the Artifact's power. It draws on the user's negativity to create an illusion.","TWN":"雖然有點荒謬，但這就是人造神器的力量。它會使使用者陷入負面的幻想當中。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저 같은 경우에는 사디스트적 취향을 지닌 고철을 만났습니다. 의문이군요.","JPN":"私の場合、サディスティックな趣味を持つ鉄くずに会いました。疑問です。","ENG":"In my case, I encountered the sadistic scrap metal. Odd.","TWN":"像我就是遇到有虐待傾向的廢鐵，真是奇妙。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"기껏 구해 놨더니 자발적으로 걸어 들어오다니. 제정신이 아니군.","JPN":"せっかく救ってやったのに、自分の足で入ってくるなんて。正気じゃないな。","ENG":"I saved you and you just walk back in here voluntarily? You're insane.","TWN":"好不容易才把你們弄出去，結果你們又自己闖進來，真是腦袋有問題。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리타까지는 안타까운 희생으로 끝맺을 수 있었습니다만, 대시까지 휘말린 이상 어쩔 수 없었습니다.","JPN":"リタまでは残念な犠牲に済ませることができたのですが、ダッシュまで引き込まれた以上、致し方ありませんでした。","ENG":"Your sacrifice, I can live with, although it would be a shame. But with Dash involved, I have no choice but to intervene.","TWN":"麗塔犧牲是沒問題，但是連黛西也一起拖下水的話，我就無法不出手。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니가 절 구하려다가 그렇게 되셨는걸요! 제가 어떻게 가만히 있을 수 있겠어요?","JPN":"お姉ちゃんが私を助けようとしてそうなったじゃないですか！　私、じっとしていられません。","ENG":"You tried to save me, Rita! So how can I just leave you here?","TWN":"姊姊是因為要救我才變成這樣的！我怎麼可以坐視不管呢？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 저걸 쓰러트리면 되는 겁니까?","JPN":"それで、あれを倒せばいいのですか？","ENG":"So, that is what we need to defeat?","TWN":"所以，現在是要打倒她嗎？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"환상이지만 리타와 싸워야 한다니, 대표로서 눈물이 앞을 가리는군요.","JPN":"幻ですけど、リタと戦わねばならないとは。代表として涙が止まりません。","ENG":"It may be an illusion, but it is still Rita. As your boss, my eyes are covered with tears.","TWN":"雖然只是幻想，沒想到竟然要對付麗塔，身為BOSS，我的淚水擋住了視線。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"아, 참고로 저희 회사는 직원의 취향을 존중해드리니 큰 걱정 마시길.","JPN":"あ、ちなみに我が社はスタッフの趣味も尊重していますので、ご心配なく。","ENG":"Oh, but just so you know, the company respects all of our employee's tastes. So do not worry.","TWN":"對了，提醒一下，我們公司很尊重員工的興趣，你不用擔心。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"닥쳐. 나도 갑자기 변해서 곤란한 참이었다고.","JPN":"黙れ。私もいきなり変わったから困ってたんだ。","ENG":"Shut up. I'm also annoyed by how I suddenly changed, okay?","TWN":"你閉嘴，突然變成這樣我也很困擾。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"뭐, 그래도… 늦었으니 슬슬 돌아가 봐야겠지.","JPN":"ま、でも……遅くなったからそろそろ戻らないとな。","ENG":"But still... It's late, so let's head back.","TWN":"總之…時間也晚了，差不多該回家了。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"돌아가자.","JPN":"帰ろう。","ENG":"C'mon.","TWN":"走吧。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"집으로.","JPN":"お家に。","ENG":"Let's go home.","TWN":"回家。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};